<script>
    const btnShowPassword = document.getElementById('btn-show-password');
    const inputPassword = document.getElementById('input-senha');
    const passwordInputIcon = {
        show: 'fa-solid fa-eye',
        hide: 'fa-solid fa-eye-slash'
    }

    btnShowPassword.addEventListener('click', () => {
        
        if(btnShowPassword.classList.contains('show')) {

            inputPassword.setAttribute('type', "text");
            btnShowPassword.children[0].className = passwordInputIcon.hide; 
            btnShowPassword.classList.remove('show');
            return;
        }

        inputPassword.setAttribute('type', "password");
        btnShowPassword.children[0].className = passwordInputIcon.show;
        btnShowPassword.classList.add('show');
         

    });

</script>